  @state _fxIO = {}  @ 22   -- session cache: fxIdent → { ins, outs, inNames, outNames }
  @state SCRATCH_NAME = 'continuum: wiring scratch'  @ 24
  @state SCRATCH_KEY = '__scratch__'  @ 25
